mapper.select:
select c.*, e.name as master_name, case when curdate() < c.begin_date then '未开班' when curdate() > c.end_date then '已结课' else '在读' end as status from clazz c left join emp e on c.master_id = e.id
c.name like concat('%', #{name}, '%')
and c.room like concat('%', #{room}, '%')
and c.master_id = #{masterId}
and c.subject = #{subject}
order by c.id desc
